"use client"

import * as React from "react"
import { Tooltip as BaseTooltip } from "@base-ui/react/tooltip"
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const TooltipProvider = BaseTooltip.Provider

const Tooltip = BaseTooltip.Root

const TooltipTrigger = BaseTooltip.Trigger

const tooltipVariants = cva(
    "z-50 overflow-hidden rounded-base border-2 border-black px-3 py-1.5 text-sm font-medium text-black shadow-brutal transition-[transform,scale,opacity] data-ending-style:scale-95 data-ending-style:opacity-0 data-starting-style:scale-95 data-starting-style:opacity-0",
    {
        variants: {
            variant: {
                default: "bg-white",
                colored: "bg-main",
            },
        },
        defaultVariants: {
            variant: "default",
        },
    }
)

type TooltipContentProps = React.ComponentPropsWithoutRef<typeof BaseTooltip.Popup> &
    VariantProps<typeof tooltipVariants> & {
        sideOffset?: number
        side?: "top" | "bottom" | "left" | "right"
        showArrow?: boolean
    }

const TooltipContent = React.forwardRef<
    React.ComponentRef<typeof BaseTooltip.Popup>,
    TooltipContentProps
>(({ className, variant, sideOffset = 8, side = "top", showArrow = true, ...props }, ref) => (
    <BaseTooltip.Portal>
        <BaseTooltip.Positioner sideOffset={sideOffset} side={side}>
            <BaseTooltip.Popup
                ref={ref}
                className={cn(tooltipVariants({ variant }), className)}
                {...props}
            />
            {showArrow && (
                <BaseTooltip.Arrow
                    className="data-[side=bottom]:top-[-8px] data-[side=left]:right-[-8px] data-[side=right]:left-[-8px] data-[side=top]:bottom-[-8px]"
                >
                    <svg width="16" height="8" viewBox="0 0 16 8" className="fill-white stroke-black stroke-2">
                        <polygon points="8,0 16,8 0,8" className={cn(variant === "colored" ? "fill-main" : "fill-white")} />
                        <polyline points="0,8 8,0 16,8" fill="none" />
                    </svg>
                </BaseTooltip.Arrow>
            )}
        </BaseTooltip.Positioner>
    </BaseTooltip.Portal>
))
TooltipContent.displayName = "TooltipContent"

export { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider, tooltipVariants }
